// src/pages/ViewAnswer.jsx
import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

export default function ViewAnswer() {
  const { attemptId } = useParams(); // From route like /view-answer/:attemptId
  const [examData, setExamData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchAnswers = async () => {
      try {
        const response = await axios.get(`http://localhost:3000/api/user/exam-history/${attemptId}`);
        setExamData(response.data);
      } catch (error) {
        console.error('Failed to fetch exam history:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchAnswers();
  }, [attemptId]);

  if (loading) return <div className="p-4">Loading...</div>;
  if (!examData) return <div className="p-4">No data available</div>;

  return (
    <div className="p-4">
      <h1 className="mb-4 text-2xl font-bold">Your Answers</h1>
      <div className="mb-4">
        <p><strong>Category:</strong> {examData.category}</p>
        <p><strong>Section:</strong> {examData.section}</p>
        <p><strong>Score:</strong> {examData.score} / {examData.totalQuestions}</p>
        <p><strong>Time Taken:</strong> {Math.floor(examData.duration / 60)} min {examData.duration % 60} sec</p>
      </div>

      <div className="space-y-4">
        {examData.answers.map((ans, index) => (
          <div key={index} className="p-3 border rounded-lg shadow">
            <p className="font-semibold">Q{index + 1}: {ans.questionText}</p>
            <p>Your Answer: <span className={ans.isCorrect ? 'text-green-600' : 'text-red-600'}>{ans.selectedOption}</span></p>
            {!ans.isCorrect && (
              <p>Correct Answer: <span className="text-green-700">{ans.correctOption}</span></p>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}
